// ── Extract & normalise every Telegram update into a flat object ──
const upd = $input.first().json;
let out = {
  update_type: 'unknown',
  chat_id: null,
  text: null,
  callback_data: null,
  callback_query_id: null,
  first_name: ''
};

if (upd.callback_query) {
  out.update_type    = 'callback';
  out.chat_id        = String(upd.callback_query.from.id);
  out.callback_data  = upd.callback_query.data;
  out.callback_query_id = upd.callback_query.id;
  out.first_name     = upd.callback_query.from.first_name || '';
} else if (upd.message) {
  out.update_type = 'message';
  out.chat_id     = String(upd.message.chat.id);
  out.text        = (upd.message.text || '').trim();
  out.first_name  = upd.message.from.first_name || '';
}

return [{ json: out }];

// Parse callback_data like: fac_UUID, evt_UUID, cat_UUID
const raw = $json.callback_data || '';
const underscore = raw.indexOf('_');
const prefix = raw.substring(0, underscore);   // fac | evt | cat
const uuid   = raw.substring(underscore + 1);  // the UUID

return [{
  json: {
    ...$json,
    cb_prefix: prefix,
    cb_uuid:   uuid
  }
}];

// Build Telegram inline keyboard from events array
const events   = $input.all();
const chat_id  = $('Parse Callback Data').item.json.chat_id;
const cbQueryId= $('Parse Callback Data').item.json.callback_query_id;
const token    = $('Config Credential').item.json.BOT_TOKEN;

if (!events || events.length === 0) {
  return [{ json: {
    chat_id, token, cb_query_id: cbQueryId,
    text: '😔 Belum ada event aktif untuk fakultas ini. Cek lagi nanti ya!',
    keyboard: null
  }}];
}

const keyboard = events.map(e => {
  const d = new Date(e.json.event_date);
  const label = `📅 ${e.json.title} — ${d.toLocaleDateString('id-ID', {day:'numeric',month:'short',year:'numeric'})}`;
  return [{ text: label, callback_data: `evt_${e.json.id}` }];
});

return [{ json: {
  chat_id, token, cb_query_id: cbQueryId,
  text: '🎓 Pilih *workshop* yang ingin kamu daftar:',
  keyboard
}}];

// Build category keyboard with seat counts
const cats     = $input.all();
const chat_id  = $('Parse Callback Data').item.json.chat_id;
const token    = $('Config Credential').item.json.BOT_TOKEN;
const cbQueryId= $('Parse Callback Data').item.json.callback_query_id;

const keyboard = cats.map(c => {
  const cat    = c.json;
  const seats  = cat.available_seats;
  const price  = cat.price > 0 ? `Rp ${Number(cat.price).toLocaleString('id-ID')}` : 'GRATIS';
  const status = seats > 0 ? `✅ ${seats} kursi` : '❌ Penuh';
  const label  = `${cat.name} — ${price} (${status})`;
  // Disable button if no seats (send a no-op callback)
  const cb_data = seats > 0 ? `cat_${cat.id}` : `full_${cat.id}`;
  return [{ text: label, callback_data: cb_data }];
});

const msgLines = cats.map(c => {
  const p = c.json.price > 0 ? `Rp ${Number(c.json.price).toLocaleString('id-ID')}` : 'Gratis';
  return `• *${c.json.name}* — ${p} | Sisa: ${c.json.available_seats}/${c.json.total_seats} kursi`;
}).join('\n');

return [{ json: {
  chat_id, token, cb_query_id: cbQueryId,
  text: `🎟️ *Pilih kategori tiket:*\n\n${msgLines}\n\n_Klik tombol di bawah untuk memilih:_`,
  keyboard
}}];

// Build faculty selection keyboard
const faculties = $input.all();
const chat_id   = $('Config Credential').item.json.chat_id;
const first_name= $('Config Credential').item.json.first_name;
const token     = $('Config Credential').item.json.BOT_TOKEN;

const keyboard = faculties.map(f => [
  { text: `🏛️ ${f.json.name} (${f.json.code})`, callback_data: `fac_${f.json.id}` }
]);

const welcome = `Halo *${first_name || 'Mahasiswa'}*! 👋\n\n`
  + `Selamat datang di *Workshop Registration Bot*!\n\n`
  + `Langkah pendaftaran:\n`
  + `1️⃣ Pilih *fakultas* kamu\n`
  + `2️⃣ Pilih *workshop* yang tersedia\n`
  + `3️⃣ Pilih kategori tiket\n`
  + `4️⃣ Isi nama, NIM, dan email\n`
  + `5️⃣ Terima kode booking ✅\n\n`
  + `*Pilih fakultasmu:*`;

return [{ json: { chat_id, token, text: welcome, keyboard } }];

// Flatten Supabase array response to a single session object (or nulls)
const rows = $input.all();
const chat_id = $('Config Credential').item.json.chat_id;
const text    = $('Config Credential').item.json.text;

if (!rows || rows.length === 0 || !rows[0].json || (Array.isArray(rows[0].json) && rows[0].json.length === 0)) {
  return [{ json: { chat_id, text, state: 'no_session', category_id: null, full_name: null, nim: null } }];
}

const session = Array.isArray(rows[0].json) ? rows[0].json[0] : rows[0].json;
return [{ json: { chat_id, text, ...session } }];

// Validate email and prepare booking data
const session = $('Extract Session Row').item.json;
const email   = session.text.trim().toLowerCase();

const emailOk = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
if (!emailOk) {
  return [{ json: { valid: false, chat_id: session.chat_id, error: `❌ Format email *${email}* tidak valid.\nCoba lagi, ketik email yang benar:` } }];
}

return [{ json: {
  valid:       true,
  chat_id:     session.chat_id,
  email:       email,
  full_name:   session.full_name,
  nim:         session.nim,
  category_id: session.category_id
}}];

// Extract student_id from Supabase upsert response
// Also build a booking code like FIK-WS-2025-0001
const rows = $input.all();
const student = Array.isArray(rows[0].json) ? rows[0].json[0] : rows[0].json;
const year    = new Date().getFullYear();
const rand    = String(Math.floor(Math.random() * 9000) + 1000); // fallback random 4-digit
const code    = `WS-${year}-${rand}`;

return [{ json: {
  student_id:   student.id,
  booking_code: code,
  email:        student.email,
  full_name:    student.full_name,
  category_id:  $('Validate Email').item.json.category_id,
  chat_id:      $('Validate Email').item.json.chat_id
}}];

// Flatten RPC response
const rows = $input.all();
const result = Array.isArray(rows[0].json) ? rows[0].json[0] : rows[0].json;
return [{ json: {
  success:     result.success,
  message:     result.message,
  booking_id:  result.booking_id,
  chat_id:     $('Extract Student ID + Build Booking Code').item.json.chat_id,
  booking_code:$('Extract Student ID + Build Booking Code').item.json.booking_code,
  full_name:   $('Extract Student ID + Build Booking Code').item.json.full_name,
  email:       $('Extract Student ID + Build Booking Code').item.json.email
}}];

